using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator;

    public ScoreCalculatorTests()
    {
        _calculator = new ScoreCalculator();
    }

    // ── CalculatePercentage ──────────────────────────────────────────

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(8, 10);

        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_PerfectScore_IsGreaterThanOrEqualTo100()
    {
        var result = _calculator.CalculatePercentage(10, 10);

        Assert.IsGreaterThanOrEqualTo(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_IsLessThan100()
    {
        var result = _calculator.CalculatePercentage(9, 10);

        Assert.IsLessThan(100.0, result);
        Assert.IsGreaterThan(0.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_ReturnsZero()
    {
        var result = _calculator.CalculatePercentage(0, 5);

        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_TotalIsZero_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(1, -5));
    }

    // ── GetGrade ─────────────────────────────────────────────────────

    [TestMethod]
    [DataRow(100.0, "A")]
    [DataRow(90.0, "A", DisplayName = "Boundary: exactly 90 → A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B", DisplayName = "Boundary: exactly 80 → B")]
    [DataRow(79.9, "C")]
    [DataRow(70.0, "C", DisplayName = "Boundary: exactly 70 → C")]
    [DataRow(69.9, "D")]
    [DataRow(60.0, "D", DisplayName = "Boundary: exactly 60 → D")]
    [DataRow(59.9, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double percentage, string expectedGrade)
    {
        var grade = _calculator.GetGrade(percentage);

        Assert.AreEqual(expectedGrade, grade);
    }

    [TestMethod]
    public void GetGrade_NegativePercentage_ReturnsF()
    {
        var grade = _calculator.GetGrade(-5.0);

        Assert.AreEqual("F", grade);
    }

    // ── NormalizeScore ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(50.0, 100.0, 50.0)]
    [DataRow(0.0, 100.0, 0.0)]
    [DataRow(100.0, 100.0, 100.0)]
    [DataRow(25.0, 50.0, 50.0)]
    public void NormalizeScore_ValidInputs_ReturnsExpected(double raw, double maxRaw, double expected)
    {
        var result = _calculator.NormalizeScore(raw, maxRaw);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void NormalizeScore_Result_IsInNormalizedRange()
    {
        var result = _calculator.NormalizeScore(75.0, 100.0);

        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_RawExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(150.0, 100.0);

        Assert.AreEqual(100.0, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_SmallRaw_IsGreaterThanZero()
    {
        var result = _calculator.NormalizeScore(1.0, 100.0);

        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }

    [TestMethod]
    public void NormalizeScore_NegativeMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, -10.0));
    }
}

